"use client";

import { useRef, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";

export default function NeuralThinking({ active }: { active: boolean }) {
  const pointsRef = useRef<THREE.Points>(null);
  const materialRef = useRef<THREE.PointsMaterial>(null);

  const particleCount = 200;

  const [positions, phases] = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    const ph = new Float32Array(particleCount);
    for (let i = 0; i < particleCount; i++) {
        // Random spread around the core
      pos[i * 3] = (Math.random() - 0.5) * 8;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 8;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 8;
      ph[i] = Math.random() * Math.PI * 2;
    }
    return [pos, ph];
  }, []);

  useFrame((state) => {
    if (!active) {
        if (materialRef.current) materialRef.current.opacity *= 0.9; // Fast fade out
        return;
    }

    if (materialRef.current) {
        materialRef.current.opacity += (0.8 - materialRef.current.opacity) * 0.1; // Fade in
    }

    if (pointsRef.current) {
      const positionsAttr = pointsRef.current.geometry.attributes.position;
      const array = positionsAttr.array as Float32Array;

      for (let i = 0; i < particleCount; i++) {
        // Swirl around the core
        const x = array[i * 3];
        const z = array[i * 3 + 2];
        const angle = Math.atan2(z, x) + 0.05;
        const radius = Math.sqrt(x*x + z*z);

        array[i * 3] = Math.cos(angle) * clampRadius(radius + Math.sin(state.clock.elapsedTime * 5 + phases[i]) * 0.05);
        array[i * 3 + 1] += Math.sin(state.clock.elapsedTime * 3 + phases[i]) * 0.02;
        array[i * 3 + 2] = Math.sin(angle) * clampRadius(radius + Math.cos(state.clock.elapsedTime * 5 + phases[i]) * 0.05);
      }
      positionsAttr.needsUpdate = true;
    }
  });

  const clampRadius = (r: number) => Math.max(1.5, Math.min(r, 6));

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={particleCount} array={positions} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial ref={materialRef} color="#0ff" size={0.05} transparent opacity={0} blending={THREE.AdditiveBlending} />
    </points>
  );
}

"use client";

import { useRef, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { Html } from "@react-three/drei";

export interface Threat {
  id: string;
  title: string;
  level: "WARNING" | "CRITICAL";
  description: string;
}

interface ThreatDetectionProps {
  threats: Threat[];
}

export default function ThreatDetection({ threats }: ThreatDetectionProps) {
  const meshRef = useRef<THREE.Mesh>(null);

  const hasThreats = threats.length > 0;
  const isCritical = threats.some(t => t.level === "CRITICAL");

  // Decide color based on level
  const color = isCritical ? "#ff0033" : "#ffaa00";

  useFrame((state, delta) => {
    if (meshRef.current) {
      if (hasThreats) {
        // Fast pulsation
        const speed = isCritical ? 10 : 5;
        const pulse = Math.sin(state.clock.elapsedTime * speed) * 0.1;
        meshRef.current.scale.set(1 + pulse, 1 + pulse, 1 + pulse);
        // Rotation
        meshRef.current.rotation.y += delta;
      } else {
        // Reset scale gracefully
        meshRef.current.scale.lerp(new THREE.Vector3(1, 1, 1), 0.1);
      }
    }
  });

  if (!hasThreats) return null;

  return (
    <group position={[0, 0, 0]}>
      <mesh ref={meshRef}>
        {/* Large outer sphere that encompasses the core */}
        <sphereGeometry args={[3, 32, 32]} />
        <meshBasicMaterial 
          color={color} 
          wireframe 
          transparent 
          opacity={0.15} 
          blending={THREE.AdditiveBlending}
        />
      </mesh>

      {/* 2D Overlay for Threat Readout */}
      <Html position={[0, 3.5, 0]} center zIndexRange={[100, 0]}>
        <div className="flex flex-col gap-2 items-center pointer-events-none">
          {threats.map(threat => (
            <div 
              key={threat.id} 
              className={`px-4 py-2 border rounded-md backdrop-blur-md animate-pulse uppercase tracking-widest text-xs font-bold pointer-events-auto
              ${threat.level === 'CRITICAL' ? 'border-red-500 bg-red-900/30 text-red-400' : 'border-amber-500 bg-amber-900/30 text-amber-400'}
              `}
            >
              ⚠ {threat.title}
            </div>
          ))}
        </div>
      </Html>
    </group>
  );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function VoiceInterface() {
  const [isListening, setIsListening] = useState(false);

  const toggleListening = () => {
    setIsListening((prev) => !prev);
  };

  return (
    <div className="fixed bottom-8 right-8 z-50 flex flex-col items-center">
      <AnimatePresence>
        {isListening && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.8, y: 20 }}
            className="mb-4 glass-panel p-3 px-6 rounded-full flex gap-1 items-center"
          >
            {/* Simple CSS Waveform animation */}
            <span className="text-[var(--color-harvey-cyan)] text-xs uppercase tracking-widest font-bold mr-3 animate-pulse">
              Listening...
            </span>
            <div className="flex gap-1 h-4 items-end">
              {[1, 2, 3, 4, 5].map((i) => (
                <motion.div
                  key={i}
                  className="w-1 bg-[var(--color-harvey-gold)] rounded-t-sm"
                  animate={{
                    height: ["20%", "100%", "20%"],
                  }}
                  transition={{
                    duration: 0.6 + Math.random() * 0.4,
                    repeat: Infinity,
                    ease: "easeInOut",
                    delay: i * 0.1,
                  }}
                />
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <button
        onClick={toggleListening}
        className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 relative ${
          isListening 
            ? "bg-[var(--color-harvey-cyan)] bg-opacity-20 border-2 border-[var(--color-harvey-cyan)] shadow-[0_0_20px_rgba(0,255,255,0.4)]" 
            : "glass-panel bg-opacity-40 hover:bg-white hover:bg-opacity-10"
        }`}
      >
        {/* Glow effect when active */}
        {isListening && (
          <motion.div
            className="absolute inset-0 rounded-full border border-[var(--color-harvey-cyan)] pointer-events-none"
            animate={{
              scale: [1, 1.5, 2],
              opacity: [0.8, 0, 0],
            }}
            transition={{
              duration: 2,
              repeat: Infinity,
              ease: "easeOut",
            }}
          />
        )}

        {/* Microphone SVG */}
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          width="24" 
          height="24" 
          viewBox="0 0 24 24" 
          fill="none" 
          stroke={isListening ? "var(--color-harvey-cyan)" : "var(--color-harvey-gold)"} 
          strokeWidth="2" 
          strokeLinecap="round" 
          strokeLinejoin="round"
        >
          <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z" />
          <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
          <line x1="12" x2="12" y1="19" y2="22" />
        </svg>
      </button>
    </div>
  );
}
